static vector<tag_t> CollectCoordinateSystemTags(NXOpen::Part* part)
{
    vector<tag_t> tags;
    if (part == NULL)
    {
        return tags;
    }

    try
    {
        NXOpen::CoordinateSystemCollection* coordinateSystems = part->CoordinateSystems();
        for (NXOpen::CoordinateSystemCollection::iterator it = coordinateSystems->begin();
            it != coordinateSystems->end(); ++it)
        {
            NXOpen::CoordinateSystem* coordinateSystem = *it;
            if (coordinateSystem != NULL)
            {
                tags.push_back(coordinateSystem->Tag());
            }
        }
    }
    catch (exception&)
    {
    }
    return tags;
}

static void DeleteNewCoordinateSystems(NXOpen::Part* part, const vector<tag_t>& baselineTags)
{
    if (part == NULL)
    {
        return;
    }

    tag_t currentWcsTag = NULL_TAG;
    try
    {
        NXOpen::CartesianCoordinateSystem* currentWcs = part->WCS()->CoordinateSystem();
        if (currentWcs != NULL)
        {
            currentWcsTag = currentWcs->Tag();
        }
    }
    catch (exception&)
    {
    }

    vector<NXOpen::TaggedObject*> objectsToDelete;
    try
    {
        NXOpen::CoordinateSystemCollection* coordinateSystems = part->CoordinateSystems();
        for (NXOpen::CoordinateSystemCollection::iterator it = coordinateSystems->begin();
            it != coordinateSystems->end(); ++it)
        {
            NXOpen::CoordinateSystem* coordinateSystem = *it;
            if (coordinateSystem == NULL)
            {
                continue;
            }

            const tag_t coordinateSystemTag = coordinateSystem->Tag();
            if (coordinateSystemTag != NULL_TAG &&
                coordinateSystemTag != currentWcsTag &&
                std::find(baselineTags.begin(), baselineTags.end(), coordinateSystemTag) == baselineTags.end())
            {
                objectsToDelete.push_back(coordinateSystem);
            }
        }
    }
    catch (exception&)
    {
        return;
    }

    if (objectsToDelete.empty())
    {
        return;
    }

    try
    {
        NXOpen::Session::UndoMarkId markId1 =
            theSession->SetUndoMark(NXOpen::Session::MarkVisibilityInvisible, "Delete temporary coordinate systems");
        theSession->UpdateManager()->ClearErrorList();
        (void)theSession->SetUndoMark(NXOpen::Session::MarkVisibilityVisible, "Delete temporary coordinate systems");
        (void)theSession->UpdateManager()->AddObjectsToDeleteList(objectsToDelete);
        NXOpen::Session::UndoMarkId id1 = theSession->NewestVisibleUndoMark();
        (void)theSession->UpdateManager()->DoUpdate(id1);
        theSession->DeleteUndoMark(markId1, NULL);
    }
    catch (exception&)
    {
    }
}

static void RestoreWcsAndDeleteTemporary(NXOpen::Part* part, NXOpen::CartesianCoordinateSystem*& previousWcs, bool& wcsChanged, const vector<tag_t>& baselineTags)
{
    if (part == NULL)
    {
        return;
    }

    if (wcsChanged && previousWcs != NULL)
    {
        NXOpen::CartesianCoordinateSystem* replacedWcs = NULL;
        try
        {
            replacedWcs = part->WCS()->SetCoordinateSystem(previousWcs);
        }
        catch (exception&)
        {
        }
        wcsChanged = false;
        previousWcs = NULL;
        DeleteTemporaryObject(replacedWcs);
    }

    DeleteNewCoordinateSystems(part, baselineTags);
}

static bool IsSingleCornerMode(NXOpen::BlockStyler::Enumeration* createModeBlock)
{
    if (createModeBlock == NULL)
    {
        return false;
    }

    try
    {
        PropertyList* createModeProps = createModeBlock->GetProperties();
        int createModeIndex = createModeProps->GetEnum("Value");
        delete createModeProps;
        createModeProps = NULL;
        if (createModeIndex == 1)
        {
            return true;
        }
    }
    catch (exception&)
    {
    }

    try
    {
        PropertyList* createModeProps = createModeBlock->GetProperties();
        NXString createModeValue = createModeProps->GetEnumAsString("Value");
        delete createModeProps;
        createModeProps = NULL;

        const char* utf8Text = createModeValue.GetUTF8Text();
        const char* localeText = createModeValue.GetLocaleText();
        return (utf8Text != NULL && strstr(utf8Text, "µĄ") != NULL) ||
            (localeText != NULL && strstr(localeText, "µĄ") != NULL);
    }
    catch (exception&)
    {
        return false;
    }
}

