static void SetSelectionFilterForMode(NXOpen::BlockStyler::SelectObject* selectionBlock, bool singleCornerMode)
{
    if (selectionBlock == NULL)
    {
        return;
    }

    const char* phase = "SetSelectionFilterForMode.prepare";
    PropertyList* selectionProps = NULL;
    try
    {
        Selection::SelectionAction action = Selection::SelectionActionClearAndEnableSpecific;
        std::vector<Selection::MaskTriple> maskArray(1);
        if (singleCornerMode)
        {
            maskArray[0] = Selection::MaskTriple(UF_solid_type, UF_solid_body_subtype, UF_UI_SEL_FEATURE_ANY_EDGE);
        }
        else
        {
            maskArray[0] = Selection::MaskTriple(UF_solid_type, UF_solid_body_subtype, UF_UI_SEL_FEATURE_ANY_FACE);
        }

        phase = "SetSelectionFilterForMode.GetProperties";
        selectionProps = selectionBlock->GetProperties();
        phase = "SetSelectionFilterForMode.SetSelectionFilter";
        selectionProps->SetSelectionFilter("SelectionFilter", action, maskArray);
        delete selectionProps;
        selectionProps = NULL;
    }
    catch (exception& ex)
    {
        if (selectionProps != NULL)
        {
            delete selectionProps;
            selectionProps = NULL;
        }
        ShowBlockStylerError(ex);
    }
}

static void SyncCreateModeControls(NXOpen::BlockStyler::SelectObject* faceSelectionBlock, NXOpen::BlockStyler::SelectObject* edgeSelectionBlock, bool singleCornerMode)
{
    const char* phase = "SyncCreateModeControls.enter";
    try
    {
        if (edgeSelectionBlock == NULL)
        {
            if (faceSelectionBlock != NULL)
            {
                phase = "SyncCreateModeControls.face SetShow true";
                faceSelectionBlock->SetShow(true);
                phase = "SyncCreateModeControls.face SetEnable true";
                faceSelectionBlock->SetEnable(true);
            }
            return;
        }

        if (faceSelectionBlock != NULL)
        {
            phase = "SyncCreateModeControls.face SetShow";
            faceSelectionBlock->SetShow(!singleCornerMode);
            phase = "SyncCreateModeControls.face SetEnable";
            faceSelectionBlock->SetEnable(!singleCornerMode);
        }
        phase = "SyncCreateModeControls.edge SetShow";
        edgeSelectionBlock->SetShow(singleCornerMode);
        phase = "SyncCreateModeControls.edge SetEnable";
        edgeSelectionBlock->SetEnable(singleCornerMode);
    }
    catch (exception& ex)
    {
        ShowBlockStylerError(ex);
    }
}

static bool IsSamePoint(const NXOpen::Point3d& point1, const NXOpen::Point3d& point2)
{
    return fabs(point1.X - point2.X) < 0.001 &&
        fabs(point1.Y - point2.Y) < 0.001 &&
        fabs(point1.Z - point2.Z) < 0.001;
}

static double PointDistance(const NXOpen::Point3d& point1, const NXOpen::Point3d& point2)
{
    double dx = point1.X - point2.X;
    double dy = point1.Y - point2.Y;
    double dz = point1.Z - point2.Z;
    return sqrt(dx * dx + dy * dy + dz * dz);
}

static void AddUniquePoint(vector<NXOpen::Point3d>& points, const NXOpen::Point3d& point);

static bool NormalizeVector(NXOpen::Point3d& vector)
{
    double length = sqrt(vector.X * vector.X + vector.Y * vector.Y + vector.Z * vector.Z);
    if (length < 0.001)
    {
        return false;
    }

    vector.X /= length;
    vector.Y /= length;
    vector.Z /= length;
    return true;
}

static double DotVector(const NXOpen::Point3d& vector1, const NXOpen::Point3d& vector2)
{
    return vector1.X * vector2.X + vector1.Y * vector2.Y + vector1.Z * vector2.Z;
}

static bool GetPlanarFaceNormal(NXOpen::Face* face, NXOpen::Point3d& normal)
{
    if (face == NULL || face->SolidFaceType() != NXOpen::Face::FaceTypePlanar)
    {
        return false;
    }

    vector<NXOpen::Edge*> edges = face->GetEdges();
    vector<NXOpen::Point3d> points;
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d vertex1;
        NXOpen::Point3d vertex2;
        edges[i]->GetVertices(&vertex1, &vertex2);
        AddUniquePoint(points, vertex1);
        AddUniquePoint(points, vertex2);
    }

    if (points.size() < 3)
    {
        return false;
    }

    NXOpen::Point3d axisU = {
        points[1].X - points[0].X,
        points[1].Y - points[0].Y,
        points[1].Z - points[0].Z
    };
    if (!NormalizeVector(axisU))
    {
        return false;
    }

    for (size_t i = 2; i < points.size(); i++)
    {
        NXOpen::Point3d vectorToPoint = {
            points[i].X - points[0].X,
            points[i].Y - points[0].Y,
            points[i].Z - points[0].Z
        };
        normal.X = axisU.Y * vectorToPoint.Z - axisU.Z * vectorToPoint.Y;
        normal.Y = axisU.Z * vectorToPoint.X - axisU.X * vectorToPoint.Z;
        normal.Z = axisU.X * vectorToPoint.Y - axisU.Y * vectorToPoint.X;
        if (NormalizeVector(normal))
        {
            return true;
        }
    }

    return false;
}

static bool GetEdgeDirection(NXOpen::Edge* edge, NXOpen::Point3d& direction)
{
    if (edge == NULL)
    {
        return false;
    }

    NXOpen::Point3d vertex1;
    NXOpen::Point3d vertex2;
    edge->GetVertices(&vertex1, &vertex2);
    direction.X = vertex2.X - vertex1.X;
    direction.Y = vertex2.Y - vertex1.Y;
    direction.Z = vertex2.Z - vertex1.Z;
    return NormalizeVector(direction);
}

static void AskEdgeMappedVertices(NXOpen::Edge* edge, NXOpen::Point3d& point1, NXOpen::Point3d& point2)
{
    NXOpen::Point3d vertex1;
    NXOpen::Point3d vertex2;
    edge->GetVertices(&vertex1, &vertex2);

    double inputPoint1[3] = { vertex1.X, vertex1.Y, vertex1.Z };
    double inputPoint2[3] = { vertex2.X, vertex2.Y, vertex2.Z };
    double outputPoint1[3];
    double outputPoint2[3];
    UF_CSYS_map_point(UF_CSYS_WORK_COORDS, inputPoint1, UF_CSYS_ROOT_WCS_COORDS, outputPoint1);
    UF_CSYS_map_point(UF_CSYS_WORK_COORDS, inputPoint2, UF_CSYS_ROOT_WCS_COORDS, outputPoint2);

    point1.X = outputPoint1[0];
    point1.Y = outputPoint1[1];
    point1.Z = outputPoint1[2];
    point2.X = outputPoint2[0];
    point2.Y = outputPoint2[1];
    point2.Z = outputPoint2[2];
}

static void AddUniquePoint(vector<NXOpen::Point3d>& points, const NXOpen::Point3d& point)
{
    for (size_t i = 0; i < points.size(); i++)
    {
        if (IsSamePoint(points[i], point))
        {
            return;
        }
    }

    points.push_back(point);
}

static bool GetBodyVertexCenter(NXOpen::Body* body, NXOpen::Point3d& center)
{
    if (body == NULL)
    {
        return false;
    }

    vector<NXOpen::Point3d> points;
    vector<NXOpen::Edge*> edges = body->GetEdges();
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        edges[i]->GetVertices(&point1, &point2);
        AddUniquePoint(points, point1);
        AddUniquePoint(points, point2);
    }

    if (points.empty())
    {
        return false;
    }

    center = { 0.0, 0.0, 0.0 };
    for (size_t i = 0; i < points.size(); i++)
    {
        center.X += points[i].X;
        center.Y += points[i].Y;
        center.Z += points[i].Z;
    }
    center.X /= static_cast<double>(points.size());
    center.Y /= static_cast<double>(points.size());
    center.Z /= static_cast<double>(points.size());
    return true;
}

static NXOpen::Xform* CreateFaceEdgeAlignedXform(NXOpen::Face* face, NXOpen::Body* body, NXOpen::Part* part)
{
    if (face == NULL || part == NULL || face->SolidFaceType() != NXOpen::Face::FaceTypePlanar)
    {
        return NULL;
    }

    NXOpen::Point3d normal;
    if (!GetPlanarFaceNormal(face, normal))
    {
        return NULL;
    }

    vector<NXOpen::Edge*> edges = face->GetEdges();
    vector<NXOpen::Point3d> facePoints;
    NXOpen::Point3d xAxis = { 0.0, 0.0, 0.0 };
    double bestLength = 0.0;
    for (size_t i = 0; i < edges.size(); i++)
    {
        NXOpen::Edge* edge = edges[i];
        if (edge == NULL)
        {
            continue;
        }

        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        edge->GetVertices(&point1, &point2);
        AddUniquePoint(facePoints, point1);
        AddUniquePoint(facePoints, point2);
        if (!IsStraightEdge(edge))
        {
            continue;
        }

        NXOpen::Point3d edgeDirection = {
            point2.X - point1.X,
            point2.Y - point1.Y,
            point2.Z - point1.Z
        };
        double edgeLength = sqrt(edgeDirection.X * edgeDirection.X +
            edgeDirection.Y * edgeDirection.Y +
            edgeDirection.Z * edgeDirection.Z);
        if (edgeLength <= bestLength || !NormalizeVector(edgeDirection))
        {
            continue;
        }

        double normalComponent = DotVector(edgeDirection, normal);
        edgeDirection.X -= normal.X * normalComponent;
        edgeDirection.Y -= normal.Y * normalComponent;
        edgeDirection.Z -= normal.Z * normalComponent;
        if (!NormalizeVector(edgeDirection))
        {
            continue;
        }

        bestLength = edgeLength;
        xAxis = edgeDirection;
    }

    if (bestLength < 0.001 || facePoints.empty())
    {
        return NULL;
    }

    NXOpen::Point3d origin = { 0.0, 0.0, 0.0 };
    for (size_t i = 0; i < facePoints.size(); i++)
    {
        origin.X += facePoints[i].X;
        origin.Y += facePoints[i].Y;
        origin.Z += facePoints[i].Z;
    }
    origin.X /= static_cast<double>(facePoints.size());
    origin.Y /= static_cast<double>(facePoints.size());
    origin.Z /= static_cast<double>(facePoints.size());

    NXOpen::Point3d bodyCenter;
    if (GetBodyVertexCenter(body, bodyCenter))
    {
        NXOpen::Point3d faceToBody = {
            bodyCenter.X - origin.X,
            bodyCenter.Y - origin.Y,
            bodyCenter.Z - origin.Z
        };
        if (DotVector(faceToBody, normal) > 0.0)
        {
            normal.X = -normal.X;
            normal.Y = -normal.Y;
            normal.Z = -normal.Z;
        }
    }

    NXOpen::Point3d yAxis = {
        normal.Y * xAxis.Z - normal.Z * xAxis.Y,
        normal.Z * xAxis.X - normal.X * xAxis.Z,
        normal.X * xAxis.Y - normal.Y * xAxis.X
    };
    if (!NormalizeVector(yAxis))
    {
        return NULL;
    }

    NXOpen::Point3d finalOrigin = origin;
    NXOpen::Point3d finalXAxis = xAxis;
    NXOpen::Vector3d initialXVector = { xAxis.X, xAxis.Y, xAxis.Z };
    NXOpen::Vector3d initialYVector = { yAxis.X, yAxis.Y, yAxis.Z };
    NXOpen::Xform* initialXform = NULL;
    NXOpen::CartesianCoordinateSystem* initialCsys = NULL;
    try
    {
        initialXform = part->Xforms()->CreateXform(
            origin,
            initialXVector,
            initialYVector,
            NXOpen::SmartObject::UpdateOptionAfterModeling,
            1.0);
        initialCsys = part->CoordinateSystems()->CreateCoordinateSystem(
            initialXform,
            NXOpen::SmartObject::UpdateOptionAfterModeling);

        double minCorner[3] = { 0.0, 0.0, 0.0 };
        double directions[3][3] = {};
        double distances[3] = { 0.0, 0.0, 0.0 };
        if (initialCsys != NULL &&
            UF_MODL_ask_bounding_box_exact(face->Tag(), initialCsys->Tag(), minCorner, directions, distances) == 0)
        {
            finalOrigin.X = minCorner[0];
            finalOrigin.Y = minCorner[1];
            finalOrigin.Z = minCorner[2];
            for (int axis = 0; axis < 3; axis++)
            {
                finalOrigin.X += directions[axis][0] * distances[axis] * 0.5;
                finalOrigin.Y += directions[axis][1] * distances[axis] * 0.5;
                finalOrigin.Z += directions[axis][2] * distances[axis] * 0.5;
            }

            int longAxis = distances[1] > distances[0] ? 1 : 0;
            finalXAxis.X = directions[longAxis][0];
            finalXAxis.Y = directions[longAxis][1];
            finalXAxis.Z = directions[longAxis][2];
            double normalComponent = DotVector(finalXAxis, normal);
            finalXAxis.X -= normal.X * normalComponent;
            finalXAxis.Y -= normal.Y * normalComponent;
            finalXAxis.Z -= normal.Z * normalComponent;
            if (!NormalizeVector(finalXAxis))
            {
                finalXAxis = xAxis;
            }
        }
    }
    catch (exception&)
    {
        finalOrigin = origin;
        finalXAxis = xAxis;
    }

    DeleteTemporaryObject(initialCsys);
    DeleteTemporaryObject(initialXform);

    xAxis = finalXAxis;
    yAxis = {
        normal.Y * xAxis.Z - normal.Z * xAxis.Y,
        normal.Z * xAxis.X - normal.X * xAxis.Z,
        normal.X * xAxis.Y - normal.Y * xAxis.X
    };
    if (!NormalizeVector(yAxis))
    {
        return NULL;
    }

    NXOpen::Vector3d xVector = { xAxis.X, xAxis.Y, xAxis.Z };
    NXOpen::Vector3d yVector = { yAxis.X, yAxis.Y, yAxis.Z };
    return part->Xforms()->CreateXform(finalOrigin, xVector, yVector, NXOpen::SmartObject::UpdateOptionAfterModeling, 1.0);
}

static void ExtendBounds3D(const NXOpen::Point3d& point, bool& hasPoint, double& minX, double& maxX, double& minY, double& maxY, double& minZ, double& maxZ);

static NXOpen::Point3d GetPointBetween(const NXOpen::Point3d& point1, const NXOpen::Point3d& point2, double ratio)
{
    NXOpen::Point3d point = {
        point1.X + (point2.X - point1.X) * ratio,
        point1.Y + (point2.Y - point1.Y) * ratio,
        point1.Z + (point2.Z - point1.Z) * ratio
    };
    return point;
}

static bool GetEdgeEndpointNearestPick(NXOpen::Edge* edge, const NXOpen::Point3d& pickPoint, NXOpen::Point3d& cornerPoint, NXOpen::Point3d& otherPoint)
{
    if (edge == NULL)
    {
        return false;
    }

    NXOpen::Point3d point1;
    NXOpen::Point3d point2;
    edge->GetVertices(&point1, &point2);
    if (PointDistance(point1, pickPoint) <= PointDistance(point2, pickPoint))
    {
        cornerPoint = point1;
        otherPoint = point2;
    }
    else
    {
        cornerPoint = point2;
        otherPoint = point1;
    }
    return true;
}

static bool GetEdgeDirectionFromPoint(NXOpen::Edge* edge, const NXOpen::Point3d& fromPoint, NXOpen::Point3d& direction, NXOpen::Point3d& otherPoint)
{
    if (edge == NULL)
    {
        return false;
    }

    NXOpen::Point3d point1;
    NXOpen::Point3d point2;
    edge->GetVertices(&point1, &point2);
    double distance1 = PointDistance(point1, fromPoint);
    double distance2 = PointDistance(point2, fromPoint);
    if (distance1 > 0.001 && distance2 > 0.001)
    {
        return false;
    }

    otherPoint = distance1 <= distance2 ? point2 : point1;
    direction.X = otherPoint.X - fromPoint.X;
    direction.Y = otherPoint.Y - fromPoint.Y;
    direction.Z = otherPoint.Z - fromPoint.Z;
    return NormalizeVector(direction);
}

static NXOpen::Xform* CreatePickedCornerBaseXform(NXOpen::Body* body, NXOpen::Edge* pickedEdge, const NXOpen::Point3d& pickPoint, NXOpen::Part* part)
{
    if (body == NULL || pickedEdge == NULL || part == NULL || !IsStraightEdge(pickedEdge))
    {
        return NULL;
    }

    NXOpen::Point3d cornerPoint;
    NXOpen::Point3d pickedOtherPoint;
    if (!GetEdgeEndpointNearestPick(pickedEdge, pickPoint, cornerPoint, pickedOtherPoint))
    {
        return NULL;
    }

    NXOpen::Point3d pickedDirection = {
        pickedOtherPoint.X - cornerPoint.X,
        pickedOtherPoint.Y - cornerPoint.Y,
        pickedOtherPoint.Z - cornerPoint.Z
    };
    if (!NormalizeVector(pickedDirection))
    {
        return NULL;
    }

    struct BaseEdgeCandidate
    {
        NXOpen::Edge* edge;
        NXOpen::Point3d direction;
        NXOpen::Point3d otherPoint;
        double length;
    };

    vector<BaseEdgeCandidate> candidates;
    vector<NXOpen::Edge*> bodyEdges = body->GetEdges();
    for (size_t i = 0; i < bodyEdges.size(); i++)
    {
        NXOpen::Edge* candidateEdge = bodyEdges[i];
        if (candidateEdge == NULL || candidateEdge == pickedEdge || !IsStraightEdge(candidateEdge))
        {
            continue;
        }

        NXOpen::Point3d direction;
        NXOpen::Point3d otherPoint;
        if (!GetEdgeDirectionFromPoint(candidateEdge, cornerPoint, direction, otherPoint))
        {
            continue;
        }
        if (fabs(DotVector(direction, pickedDirection)) > 0.05)
        {
            continue;
        }

        BaseEdgeCandidate candidate;
        candidate.edge = candidateEdge;
        candidate.direction = direction;
        candidate.otherPoint = otherPoint;
        candidate.length = candidateEdge->GetLength();
        candidates.push_back(candidate);
    }

    int bestIndex1 = -1;
    int bestIndex2 = -1;
    double bestScore = -1.0;
    for (size_t i = 0; i < candidates.size(); i++)
    {
        for (size_t j = i + 1; j < candidates.size(); j++)
        {
            if (fabs(DotVector(candidates[i].direction, candidates[j].direction)) > 0.05)
            {
                continue;
            }
            double score = candidates[i].length + candidates[j].length;
            if (score > bestScore)
            {
                bestScore = score;
                bestIndex1 = static_cast<int>(i);
                bestIndex2 = static_cast<int>(j);
            }
        }
    }

    if (bestIndex1 < 0 || bestIndex2 < 0)
    {
        return NULL;
    }

    NXOpen::Point3d xAxis = candidates[bestIndex1].direction;
    NXOpen::Point3d yAxis = candidates[bestIndex2].direction;
    NXOpen::Point3d zAxis = {
        xAxis.Y * yAxis.Z - xAxis.Z * yAxis.Y,
        xAxis.Z * yAxis.X - xAxis.X * yAxis.Z,
        xAxis.X * yAxis.Y - xAxis.Y * yAxis.X
    };
    if (!NormalizeVector(zAxis))
    {
        return NULL;
    }
    if (DotVector(zAxis, pickedDirection) > 0.0)
    {
        yAxis.X = -yAxis.X;
        yAxis.Y = -yAxis.Y;
        yAxis.Z = -yAxis.Z;
        zAxis.X = -zAxis.X;
        zAxis.Y = -zAxis.Y;
        zAxis.Z = -zAxis.Z;
    }
    if (fabs(DotVector(zAxis, pickedDirection)) < 0.95)
    {
        return NULL;
    }

    NXOpen::Point3d midpoint1 = GetPointBetween(cornerPoint, candidates[bestIndex1].otherPoint, 0.5);
    NXOpen::Point3d midpoint2 = GetPointBetween(cornerPoint, candidates[bestIndex2].otherPoint, 0.5);
    NXOpen::Point3d origin = {
        cornerPoint.X + (candidates[bestIndex1].otherPoint.X - cornerPoint.X) * 0.5 + (candidates[bestIndex2].otherPoint.X - cornerPoint.X) * 0.5,
        cornerPoint.Y + (candidates[bestIndex1].otherPoint.Y - cornerPoint.Y) * 0.5 + (candidates[bestIndex2].otherPoint.Y - cornerPoint.Y) * 0.5,
        cornerPoint.Z + (candidates[bestIndex1].otherPoint.Z - cornerPoint.Z) * 0.5 + (candidates[bestIndex2].otherPoint.Z - cornerPoint.Z) * 0.5
    };

    NXOpen::Vector3d xVector = { xAxis.X, xAxis.Y, xAxis.Z };
    NXOpen::Vector3d yVector = { yAxis.X, yAxis.Y, yAxis.Z };
    return part->Xforms()->CreateXform(origin, xVector, yVector, NXOpen::SmartObject::UpdateOptionAfterModeling, 1.0);
}

static bool GetBodyMappedBasePlaneBounds(NXOpen::Body* body, double zTolerance, double& minX, double& maxX, double& minY, double& maxY, double& minZ, double& maxZ)
{
    if (body == NULL)
    {
        return false;
    }

    bool hasPoint = false;
    vector<NXOpen::Edge*> edges = body->GetEdges();
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        AskEdgeMappedVertices(edges[i], point1, point2);
        if (fabs(point1.Z) <= zTolerance)
        {
            ExtendBounds3D(point1, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
        }
        if (fabs(point2.Z) <= zTolerance)
        {
            ExtendBounds3D(point2, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
        }
    }

    return hasPoint;
}
struct ProjectedPoint
{
    double x;
    double y;
};

struct SkirtInfo
{
    bool xMinus;
    bool xPlus;
    bool yMinus;
    bool yPlus;
    double xMinusWidth;
    double xPlusWidth;
    double yMinusWidth;
    double yPlusWidth;
    double bodyMinX;
    double bodyMaxX;
    double bodyMinY;
    double bodyMaxY;
};

static double Cross2D(const ProjectedPoint& origin, const ProjectedPoint& point1, const ProjectedPoint& point2)
{
    return (point1.x - origin.x) * (point2.y - origin.y) -
        (point1.y - origin.y) * (point2.x - origin.x);
}

static bool GetFourRightAngleFaceArea(NXOpen::Face* face, double& area)
{
    area = 0.0;
    if (face == NULL || face->SolidFaceType() != NXOpen::Face::FaceTypePlanar)
    {
        return false;
    }

    vector<NXOpen::Edge*> edges = face->GetEdges();
    vector<NXOpen::Point3d> points;
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d vertex1;
        NXOpen::Point3d vertex2;
        edges[i]->GetVertices(&vertex1, &vertex2);
        if (PointDistance(vertex1, vertex2) < 0.001)
        {
            continue;
        }

        AddUniquePoint(points, vertex1);
        AddUniquePoint(points, vertex2);
    }

    if (points.size() < 4)
    {
        return false;
    }

    NXOpen::Point3d origin = points[0];
    NXOpen::Point3d axisU;
    bool hasAxisU = false;
    for (size_t i = 1; i < points.size(); i++)
    {
        if (PointDistance(origin, points[i]) > 0.001)
        {
            axisU.X = points[i].X - origin.X;
            axisU.Y = points[i].Y - origin.Y;
            axisU.Z = points[i].Z - origin.Z;
            hasAxisU = true;
            break;
        }
    }
    if (!hasAxisU)
    {
        return false;
    }
    double axisULength = sqrt(axisU.X * axisU.X + axisU.Y * axisU.Y + axisU.Z * axisU.Z);
    axisU.X /= axisULength;
    axisU.Y /= axisULength;
    axisU.Z /= axisULength;

    NXOpen::Point3d normal;
    bool hasNormal = false;
    for (size_t i = 1; i < points.size(); i++)
    {
        NXOpen::Point3d vectorToPoint = {
            points[i].X - origin.X,
            points[i].Y - origin.Y,
            points[i].Z - origin.Z
        };
        normal.X = axisU.Y * vectorToPoint.Z - axisU.Z * vectorToPoint.Y;
        normal.Y = axisU.Z * vectorToPoint.X - axisU.X * vectorToPoint.Z;
        normal.Z = axisU.X * vectorToPoint.Y - axisU.Y * vectorToPoint.X;
        double normalLength = sqrt(normal.X * normal.X + normal.Y * normal.Y + normal.Z * normal.Z);
        if (normalLength > 0.001)
        {
            normal.X /= normalLength;
            normal.Y /= normalLength;
            normal.Z /= normalLength;
            hasNormal = true;
            break;
        }
    }
    if (!hasNormal)
    {
        return false;
    }

    NXOpen::Point3d axisV = {
        normal.Y * axisU.Z - normal.Z * axisU.Y,
        normal.Z * axisU.X - normal.X * axisU.Z,
        normal.X * axisU.Y - normal.Y * axisU.X
    };

    vector<ProjectedPoint> projectedPoints;
    for (size_t i = 0; i < points.size(); i++)
    {
        NXOpen::Point3d vectorToPoint = {
            points[i].X - origin.X,
            points[i].Y - origin.Y,
            points[i].Z - origin.Z
        };
        ProjectedPoint projectedPoint = {
            vectorToPoint.X * axisU.X + vectorToPoint.Y * axisU.Y + vectorToPoint.Z * axisU.Z,
            vectorToPoint.X * axisV.X + vectorToPoint.Y * axisV.Y + vectorToPoint.Z * axisV.Z
        };
        projectedPoints.push_back(projectedPoint);
    }

    std::sort(projectedPoints.begin(), projectedPoints.end(), [](const ProjectedPoint& point1, const ProjectedPoint& point2) {
        if (fabs(point1.x - point2.x) > 0.001)
        {
            return point1.x < point2.x;
        }
        return point1.y < point2.y;
    });

    vector<ProjectedPoint> hull;
    for (size_t i = 0; i < projectedPoints.size(); i++)
    {
        while (hull.size() >= 2 && Cross2D(hull[hull.size() - 2], hull[hull.size() - 1], projectedPoints[i]) <= 0.001)
        {
            hull.pop_back();
        }
        hull.push_back(projectedPoints[i]);
    }
    size_t lowerHullSize = hull.size();
    for (size_t i = projectedPoints.size(); i > 0; i--)
    {
        ProjectedPoint point = projectedPoints[i - 1];
        while (hull.size() > lowerHullSize && Cross2D(hull[hull.size() - 2], hull[hull.size() - 1], point) <= 0.001)
        {
            hull.pop_back();
        }
        hull.push_back(point);
    }
    if (!hull.empty())
    {
        hull.pop_back();
    }

    if (hull.size() != 4)
    {
        return false;
    }

    for (size_t i = 0; i < hull.size(); i++)
    {
        const ProjectedPoint& previous = hull[(i + hull.size() - 1) % hull.size()];
        const ProjectedPoint& current = hull[i];
        const ProjectedPoint& next = hull[(i + 1) % hull.size()];
        double vector1[2] = { previous.x - current.x, previous.y - current.y };
        double vector2[2] = { next.x - current.x, next.y - current.y };
        double length1 = sqrt(vector1[0] * vector1[0] + vector1[1] * vector1[1]);
        double length2 = sqrt(vector2[0] * vector2[0] + vector2[1] * vector2[1]);
        double dot = vector1[0] * vector2[0] + vector1[1] * vector2[1];
        if (length1 < 0.001 || length2 < 0.001 || fabs(dot / (length1 * length2)) > 0.001)
        {
            return false;
        }
    }

    area = fabs(Cross2D(hull[0], hull[1], hull[2]));
    return area > 0.001;
}

static bool GetPlanarFaceHullArea(NXOpen::Face* face, double& area)
{
    area = 0.0;
    if (face == NULL || face->SolidFaceType() != NXOpen::Face::FaceTypePlanar)
    {
        return false;
    }

    vector<NXOpen::Edge*> edges = face->GetEdges();
    vector<NXOpen::Point3d> points;
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d vertex1;
        NXOpen::Point3d vertex2;
        edges[i]->GetVertices(&vertex1, &vertex2);
        if (PointDistance(vertex1, vertex2) < 0.001)
        {
            continue;
        }

        AddUniquePoint(points, vertex1);
        AddUniquePoint(points, vertex2);
    }

    if (points.size() < 3)
    {
        return false;
    }

    NXOpen::Point3d origin = points[0];
    NXOpen::Point3d axisU;
    bool hasAxisU = false;
    for (size_t i = 1; i < points.size(); i++)
    {
        if (PointDistance(origin, points[i]) > 0.001)
        {
            axisU.X = points[i].X - origin.X;
            axisU.Y = points[i].Y - origin.Y;
            axisU.Z = points[i].Z - origin.Z;
            hasAxisU = true;
            break;
        }
    }
    if (!hasAxisU)
    {
        return false;
    }
    double axisULength = sqrt(axisU.X * axisU.X + axisU.Y * axisU.Y + axisU.Z * axisU.Z);
    axisU.X /= axisULength;
    axisU.Y /= axisULength;
    axisU.Z /= axisULength;

    NXOpen::Point3d normal;
    bool hasNormal = false;
    for (size_t i = 1; i < points.size(); i++)
    {
        NXOpen::Point3d vectorToPoint = {
            points[i].X - origin.X,
            points[i].Y - origin.Y,
            points[i].Z - origin.Z
        };
        normal.X = axisU.Y * vectorToPoint.Z - axisU.Z * vectorToPoint.Y;
        normal.Y = axisU.Z * vectorToPoint.X - axisU.X * vectorToPoint.Z;
        normal.Z = axisU.X * vectorToPoint.Y - axisU.Y * vectorToPoint.X;
        double normalLength = sqrt(normal.X * normal.X + normal.Y * normal.Y + normal.Z * normal.Z);
        if (normalLength > 0.001)
        {
            normal.X /= normalLength;
            normal.Y /= normalLength;
            normal.Z /= normalLength;
            hasNormal = true;
            break;
        }
    }
    if (!hasNormal)
    {
        return false;
    }

    NXOpen::Point3d axisV = {
        normal.Y * axisU.Z - normal.Z * axisU.Y,
        normal.Z * axisU.X - normal.X * axisU.Z,
        normal.X * axisU.Y - normal.Y * axisU.X
    };

    vector<ProjectedPoint> projectedPoints;
    for (size_t i = 0; i < points.size(); i++)
    {
        NXOpen::Point3d vectorToPoint = {
            points[i].X - origin.X,
            points[i].Y - origin.Y,
            points[i].Z - origin.Z
        };
        ProjectedPoint projectedPoint = {
            vectorToPoint.X * axisU.X + vectorToPoint.Y * axisU.Y + vectorToPoint.Z * axisU.Z,
            vectorToPoint.X * axisV.X + vectorToPoint.Y * axisV.Y + vectorToPoint.Z * axisV.Z
        };
        projectedPoints.push_back(projectedPoint);
    }

    std::sort(projectedPoints.begin(), projectedPoints.end(), [](const ProjectedPoint& point1, const ProjectedPoint& point2) {
        if (fabs(point1.x - point2.x) > 0.001)
        {
            return point1.x < point2.x;
        }
        return point1.y < point2.y;
    });

    vector<ProjectedPoint> hull;
    for (size_t i = 0; i < projectedPoints.size(); i++)
    {
        while (hull.size() >= 2 && Cross2D(hull[hull.size() - 2], hull[hull.size() - 1], projectedPoints[i]) <= 0.001)
        {
            hull.pop_back();
        }
        hull.push_back(projectedPoints[i]);
    }
    size_t lowerHullSize = hull.size();
    for (size_t i = projectedPoints.size(); i > 0; i--)
    {
        ProjectedPoint point = projectedPoints[i - 1];
        while (hull.size() > lowerHullSize && Cross2D(hull[hull.size() - 2], hull[hull.size() - 1], point) <= 0.001)
        {
            hull.pop_back();
        }
        hull.push_back(point);
    }
    if (!hull.empty())
    {
        hull.pop_back();
    }
    if (hull.size() < 3)
    {
        return false;
    }

    double signedArea = 0.0;
    for (size_t i = 0; i < hull.size(); i++)
    {
        const ProjectedPoint& current = hull[i];
        const ProjectedPoint& next = hull[(i + 1) % hull.size()];
        signedArea += current.x * next.y - current.y * next.x;
    }
    area = fabs(signedArea) * 0.5;
    return area > 0.001;
}

static bool IsBodyMaxBoundaryFace(NXOpen::Face* selectedFace, NXOpen::Body* body)
{
    double selectedArea = 0.0;
    if (selectedFace == NULL || body == NULL || !GetPlanarFaceHullArea(selectedFace, selectedArea))
    {
        return false;
    }

    double maxArea = 0.0;
    vector<NXOpen::Face*> faces = body->GetFaces();
    for (size_t i = 0; i < faces.size(); i++)
    {
        double faceArea = 0.0;
        if (GetPlanarFaceHullArea(faces[i], faceArea) && faceArea > maxArea)
        {
            maxArea = faceArea;
        }
    }

    return maxArea > 0.001 && selectedArea >= maxArea - 0.001;
}

static NXOpen::Face* FindLargestRightAngleFace(NXOpen::Body* body)
{
    if (body == NULL)
    {
        return NULL;
    }

    NXOpen::Face* bestFace = NULL;
    double bestArea = 0.0;
    vector<NXOpen::Face*> faces = body->GetFaces();
    for (size_t i = 0; i < faces.size(); i++)
    {
        double faceArea = 0.0;
        if (GetFourRightAngleFaceArea(faces[i], faceArea) && faceArea > bestArea)
        {
            bestArea = faceArea;
            bestFace = faces[i];
        }
    }

    return bestFace;
}

static NXOpen::Face* FindLargestPlanarFace(NXOpen::Body* body)
{
    if (body == NULL)
    {
        return NULL;
    }

    NXOpen::Face* bestFace = NULL;
    double bestArea = 0.0;
    vector<NXOpen::Face*> faces = body->GetFaces();
    for (size_t i = 0; i < faces.size(); i++)
    {
        double faceArea = 0.0;
        if (GetPlanarFaceHullArea(faces[i], faceArea) && faceArea > bestArea)
        {
            bestArea = faceArea;
            bestFace = faces[i];
        }
    }

    return bestFace;
}

static bool GetFaceTrueArea(NXOpen::Face* face, double& area);

static NXOpen::Face* FindLargestPlanarFaceParallelToEdge(NXOpen::Body* body, NXOpen::Edge* edge)
{
    if (body == NULL || edge == NULL || workPart == NULL)
    {
        return NULL;
    }

    NXOpen::Point3d edgeDirection;
    if (!GetEdgeDirection(edge, edgeDirection))
    {
        return NULL;
    }

    NXOpen::Face* bestFace = NULL;
    double bestArea = 0.0;
    vector<NXOpen::Face*> faces = body->GetFaces();
    for (size_t i = 0; i < faces.size(); i++)
    {
        NXOpen::Point3d faceNormal;
        double faceArea = 0.0;
        if (!GetPlanarFaceNormal(faces[i], faceNormal) ||
            !GetFaceTrueArea(faces[i], faceArea))
        {
            continue;
        }

        if (fabs(DotVector(faceNormal, edgeDirection)) < 0.95)
        {
            continue;
        }

        double faceToEdgeDistance = std::numeric_limits<double>::max();
        MeasureDistance* measureDistance = NULL;
        try
        {
            measureDistance = workPart->MeasureManager()->NewDistance(NULL, MeasureManager::MeasureTypeMinimum, faces[i], edge);
            faceToEdgeDistance = measureDistance->Value();
            delete measureDistance;
            measureDistance = NULL;
        }
        catch (exception&)
        {
            if (measureDistance != NULL)
            {
                delete measureDistance;
                measureDistance = NULL;
            }
            continue;
        }

        if (faceToEdgeDistance > 0.01)
        {
            continue;
        }

        if (faceArea > bestArea)
        {
            bestArea = faceArea;
            bestFace = faces[i];
        }
    }

    return bestFace;
}

static bool GetFaceTrueArea(NXOpen::Face* face, double& area)
{
    area = 0.0;
    if (face == NULL || workPart == NULL)
    {
        return false;
    }

    NXOpen::MeasureFaces* measureFaces = NULL;
    try
    {
        NXOpen::Unit* areaUnit = workPart->UnitCollection()->GetBase("Area");
        NXOpen::Unit* lengthUnit = workPart->UnitCollection()->GetBase("Length");
        vector<NXOpen::IParameterizedSurface*> faces;
        faces.push_back(face);
        measureFaces = workPart->MeasureManager()->NewFaceProperties(areaUnit, lengthUnit, 0.99, faces);
        area = measureFaces->Area();
        delete measureFaces;
        measureFaces = NULL;
        return area > 0.001;
    }
    catch (exception&)
    {
        if (measureFaces != NULL)
        {
            delete measureFaces;
            measureFaces = NULL;
        }
        return false;
    }
}

static bool GetParallelLargeFaceThickness(
    NXOpen::Face* baseFace,
    const vector<NXOpen::Face*>& faces,
    double minAreaRatio,
    double& thickness,
    double& baseArea,
    double& matchedFaceArea,
    int& qualifiedFaceCount)
{
    thickness = 0.0;
    baseArea = 0.0;
    matchedFaceArea = 0.0;
    qualifiedFaceCount = 0;
    if (baseFace == NULL || workPart == NULL)
    {
        return false;
    }

    NXOpen::Point3d baseNormal;
    if (!GetPlanarFaceNormal(baseFace, baseNormal) || !GetFaceTrueArea(baseFace, baseArea))
    {
        return false;
    }

    double minDistance = std::numeric_limits<double>::max();
    for (size_t i = 0; i < faces.size(); i++)
    {
        NXOpen::Face* candidateFace = faces[i];
        if (candidateFace == NULL || candidateFace->Tag() == baseFace->Tag())
        {
            continue;
        }

        NXOpen::Point3d candidateNormal;
        if (!GetPlanarFaceNormal(candidateFace, candidateNormal))
        {
            continue;
        }

        if (fabs(DotVector(baseNormal, candidateNormal)) < 0.95)
        {
            continue;
        }

        double candidateArea = 0.0;
        if (!GetFaceTrueArea(candidateFace, candidateArea) ||
            candidateArea <= baseArea * minAreaRatio)
        {
            continue;
        }

        MeasureDistance* measureDistance = NULL;
        try
        {
            measureDistance = workPart->MeasureManager()->NewDistance(NULL, MeasureManager::MeasureTypeMinimum, baseFace, candidateFace);
            double distance = measureDistance->Value();
            delete measureDistance;
            measureDistance = NULL;
            if (distance <= 0.01)
            {
                continue;
            }

            qualifiedFaceCount++;

            if (distance < minDistance)
            {
                minDistance = distance;
                matchedFaceArea = candidateArea;
            }
        }
        catch (exception&)
        {
            if (measureDistance != NULL)
            {
                delete measureDistance;
                measureDistance = NULL;
            }
        }
    }

    if (minDistance == std::numeric_limits<double>::max())
    {
        return false;
    }

    thickness = minDistance;
    return true;
}

static bool EdgeTouchesPoint(NXOpen::Edge* edge, const NXOpen::Point3d& point, double tolerance, NXOpen::Point3d& edgePoint1, NXOpen::Point3d& edgePoint2)
{
    if (edge == NULL)
    {
        return false;
    }

    AskEdgeMappedVertices(edge, edgePoint1, edgePoint2);
    return PointDistance(edgePoint1, point) < tolerance ||
        PointDistance(edgePoint2, point) < tolerance;
}

static int GetConnectedThicknessCutDirection(NXOpen::Edge* jiaoEdge, const vector<NXOpen::Edge*>& bodyEdges, double banHou)
{
    if (jiaoEdge == NULL)
    {
        return 0;
    }

    NXOpen::Point3d jiaoPoint1;
    NXOpen::Point3d jiaoPoint2;
    AskEdgeMappedVertices(jiaoEdge, jiaoPoint1, jiaoPoint2);
    NXOpen::Point3d farPoint = fabs(jiaoPoint1.Z) > fabs(jiaoPoint2.Z) ? jiaoPoint1 : jiaoPoint2;

    int touchCount = 0;
    double closestDistance = std::numeric_limits<double>::max();
    double closestLength = 0.0;
    double closestDx = 0.0;
    double closestDy = 0.0;
    double closestDz = 0.0;
    for (size_t i = 0; i < bodyEdges.size(); i++)
    {
        NXOpen::Edge* candidateEdge = bodyEdges[i];
        if (candidateEdge == NULL || candidateEdge == jiaoEdge)
        {
            continue;
        }

        NXOpen::Point3d edgePoint1;
        NXOpen::Point3d edgePoint2;
        AskEdgeMappedVertices(candidateEdge, edgePoint1, edgePoint2);
        double touchDistance1 = PointDistance(edgePoint1, farPoint);
        double touchDistance2 = PointDistance(edgePoint2, farPoint);
        double touchDistance = std::min(touchDistance1, touchDistance2);
        double dx = fabs(edgePoint1.X - edgePoint2.X);
        double dy = fabs(edgePoint1.Y - edgePoint2.Y);
        double dz = fabs(edgePoint1.Z - edgePoint2.Z);
        if (touchDistance < closestDistance)
        {
            closestDistance = touchDistance;
            closestLength = candidateEdge->GetLength();
            closestDx = dx;
            closestDy = dy;
            closestDz = dz;
        }
        if (touchDistance > 0.001)
        {
            continue;
        }
        touchCount++;

        double edgeLength = candidateEdge->GetLength();
        double lengthDiff = fabs(edgeLength - banHou);
        bool isThicknessEdge = lengthDiff < 0.001;
        if (dx > 0.001 && dx >= dy && dx >= dz)
        {
            return isThicknessEdge ? 1 : 2;
        }
        if (dy > 0.001 && dy >= dx && dy >= dz)
        {
            return isThicknessEdge ? 2 : 1;
        }
    }

    return 0;
}

static bool GetEdgeOtherMappedEndpoint(NXOpen::Edge* edge, const NXOpen::Point3d& touchPoint, NXOpen::Point3d& otherPoint)
{
    if (edge == NULL)
    {
        return false;
    }

    NXOpen::Point3d point1;
    NXOpen::Point3d point2;
    AskEdgeMappedVertices(edge, point1, point2);
    double distance1 = PointDistance(point1, touchPoint);
    double distance2 = PointDistance(point2, touchPoint);
    if (distance1 < 0.001)
    {
        otherPoint = point2;
        return true;
    }
    if (distance2 < 0.001)
    {
        otherPoint = point1;
        return true;
    }
    return false;
}

static int GetEdgeXyDirection(NXOpen::Edge* edge)
{
    if (edge == NULL)
    {
        return 0;
    }

    NXOpen::Point3d point1;
    NXOpen::Point3d point2;
    AskEdgeMappedVertices(edge, point1, point2);
    double dx = fabs(point1.X - point2.X);
    double dy = fabs(point1.Y - point2.Y);
    double dz = fabs(point1.Z - point2.Z);
    if (dx > 0.001 && dx >= dy && dx >= dz)
    {
        return 1;
    }
    if (dy > 0.001 && dy >= dx && dy >= dz)
    {
        return 2;
    }
    return 0;
}

static bool AreMappedEdgesParallel(NXOpen::Edge* edge1, NXOpen::Edge* edge2)
{
    if (!IsStraightEdge(edge1) || !IsStraightEdge(edge2))
    {
        return false;
    }

    NXOpen::Point3d edge1Point1;
    NXOpen::Point3d edge1Point2;
    NXOpen::Point3d edge2Point1;
    NXOpen::Point3d edge2Point2;
    AskEdgeMappedVertices(edge1, edge1Point1, edge1Point2);
    AskEdgeMappedVertices(edge2, edge2Point1, edge2Point2);
    double vector1X = edge1Point2.X - edge1Point1.X;
    double vector1Y = edge1Point2.Y - edge1Point1.Y;
    double vector1Z = edge1Point2.Z - edge1Point1.Z;
    double vector2X = edge2Point2.X - edge2Point1.X;
    double vector2Y = edge2Point2.Y - edge2Point1.Y;
    double vector2Z = edge2Point2.Z - edge2Point1.Z;
    double length1 = sqrt(vector1X * vector1X + vector1Y * vector1Y + vector1Z * vector1Z);
    double length2 = sqrt(vector2X * vector2X + vector2Y * vector2Y + vector2Z * vector2Z);
    if (length1 < 0.001 || length2 < 0.001)
    {
        return false;
    }

    double dot = fabs((vector1X * vector2X + vector1Y * vector2Y + vector1Z * vector2Z) / (length1 * length2));
    return dot >= 0.98;
}

static bool FindSkirtInnerConnectedEdgeBranch(
    NXOpen::Edge* innerEdge,
    NXOpen::Edge* jiaoEdge,
    const vector<NXOpen::Edge*>& bodyEdges,
    double banHou,
    NXOpen::Edge*& connectedEdge,
    NXOpen::Edge*& thicknessEdge,
    int& forceDirection)
{
    connectedEdge = NULL;
    thicknessEdge = NULL;
    forceDirection = 0;
    if (!IsStraightEdge(innerEdge))
    {
        return false;
    }

    NXOpen::Point3d innerPoint1;
    NXOpen::Point3d innerPoint2;
    AskEdgeMappedVertices(innerEdge, innerPoint1, innerPoint2);
    NXOpen::Point3d farPoint = fabs(innerPoint1.Z) > fabs(innerPoint2.Z) ? innerPoint1 : innerPoint2;

    double lengthTolerance = std::max(0.01, banHou * 0.05);
    int connectedCandidateCount = 0;
    int thicknessCandidateCount = 0;
    int parallelThicknessCandidateCount = 0;
    for (size_t i = 0; i < bodyEdges.size(); i++)
    {
        NXOpen::Edge* candidateConnectedEdge = bodyEdges[i];
        if (!IsStraightEdge(candidateConnectedEdge) ||
            candidateConnectedEdge == innerEdge ||
            candidateConnectedEdge == jiaoEdge)
        {
            continue;
        }

        NXOpen::Point3d connectedOtherPoint;
        if (!GetEdgeOtherMappedEndpoint(candidateConnectedEdge, farPoint, connectedOtherPoint))
        {
            continue;
        }
        connectedCandidateCount++;

        for (size_t j = 0; j < bodyEdges.size(); j++)
        {
            NXOpen::Edge* candidateThicknessEdge = bodyEdges[j];
            if (!IsStraightEdge(candidateThicknessEdge) ||
                candidateThicknessEdge == candidateConnectedEdge ||
                candidateThicknessEdge == innerEdge ||
                candidateThicknessEdge == jiaoEdge)
            {
                continue;
            }
            if (fabs(candidateThicknessEdge->GetLength() - banHou) > lengthTolerance)
            {
                continue;
            }

            NXOpen::Point3d unusedPoint;
            if (!GetEdgeOtherMappedEndpoint(candidateThicknessEdge, connectedOtherPoint, unusedPoint))
            {
                continue;
            }
            thicknessCandidateCount++;
            if (!AreMappedEdgesParallel(candidateThicknessEdge, innerEdge))
            {
                continue;
            }
            parallelThicknessCandidateCount++;

            int direction = GetEdgeXyDirection(candidateThicknessEdge);
            if (direction == 0)
            {
                direction = GetEdgeXyDirection(candidateConnectedEdge);
            }
            if (direction == 0)
            {
                continue;
            }

            connectedEdge = candidateConnectedEdge;
            thicknessEdge = candidateThicknessEdge;
            forceDirection = direction;
            return true;
        }
    }

    return false;
}

static void CreateSkirtInnerConnectedEdgeBox(
    NXOpen::Edge* connectedEdge,
    double banHou,
    int forceDirection,
    double tearGap,
    NXOpen::CartesianCoordinateSystem* coordinateSystem,
    NXOpen::NXObject*& nXObject)
{
    nXObject = NULL;
    if (!IsStraightEdge(connectedEdge) || coordinateSystem == NULL)
    {
        return;
    }

    try
    {
        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        AskEdgeMappedVertices(connectedEdge, point1, point2);
        double dx = fabs(point1.X - point2.X);
        double dy = fabs(point1.Y - point2.Y);
        double dz = fabs(point1.Z - point2.Z);
        double centerPoint[3] = {
            (point1.X + point2.X) / 2.0,
            (point1.Y + point2.Y) / 2.0,
            (point1.Z + point2.Z) / 2.0
        };

        double tearGapHalf = tearGap / 2.0;
        double crossLength = banHou * 2.0 + tearGap * 2.0;
        double xLength = crossLength;
        double yLength = crossLength;
        double zLength = banHou * 2.0;
        int thinAxis = 0; // 1: X thin, 2: Y thin
        if (dx > 0.001 && dx >= dy && dx >= dz)
        {
            xLength = dx + tearGap * 2.0;
            yLength = tearGap;
            thinAxis = 2;
        }
        else if (dy > 0.001 && dy >= dx && dy >= dz)
        {
            xLength = tearGap;
            yLength = dy + tearGap * 2.0;
            thinAxis = 1;
        }
        else if (forceDirection == 1)
        {
            xLength = tearGap;
            yLength = crossLength;
            thinAxis = 1;
        }
        else if (forceDirection == 2)
        {
            xLength = crossLength;
            yLength = tearGap;
            thinAxis = 2;
        }
        if (thinAxis == 1)
        {
            centerPoint[0] += centerPoint[0] >= 0.0 ? -tearGapHalf : tearGapHalf;
        }
        else if (thinAxis == 2)
        {
            centerPoint[1] += centerPoint[1] >= 0.0 ? -tearGapHalf : tearGapHalf;
        }

        double outputPoint[3];
        UF_CSYS_map_point(UF_CSYS_ROOT_WCS_COORDS, centerPoint, UF_CSYS_WORK_COORDS, outputPoint);
        NXOpen::Point3d position = { outputPoint[0], outputPoint[1], outputPoint[2] };

        NXOpen::Features::ToolingBox* nullToolingBox(NULL);
        NXOpen::Features::ToolingBoxBuilder* toolingBoxBuilder =
            workPart->Features()->ToolingFeatureCollection()->CreateToolingBoxBuilder(nullToolingBox);
        toolingBoxBuilder->SetType(NXOpen::Features::ToolingBoxBuilder::TypesCenterAndLengths);
        toolingBoxBuilder->SetBoxMatrixAndPosition(coordinateSystem->Orientation()->Element(), position);
        char xFormula[256];
        char yFormula[256];
        char zFormula[256];
        sprintf_s(xFormula, sizeof(xFormula), "%f\n", xLength);
        sprintf_s(yFormula, sizeof(yFormula), "%f\n", yLength);
        sprintf_s(zFormula, sizeof(zFormula), "%f\n", zLength);
        toolingBoxBuilder->XValue()->SetFormula(xFormula);
        toolingBoxBuilder->YValue()->SetFormula(yFormula);
        toolingBoxBuilder->ZValue()->SetFormula(zFormula);
        toolingBoxBuilder->CalculateBoxSize();
        nXObject = toolingBoxBuilder->Commit();
        vector<Body*> createdBodies = toolingBoxBuilder->GetFeature()->GetBodies();
        AddFirstCreatedBody(createdBodies);
        toolingBoxBuilder->Destroy();
    }
    catch (exception& ex)
    {
        MenBanSiBian::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
}

static void ExtendBounds(double x, double y, bool& hasPoint, double& minX, double& maxX, double& minY, double& maxY)
{
    if (!hasPoint)
    {
        minX = maxX = x;
        minY = maxY = y;
        hasPoint = true;
        return;
    }

    minX = std::min(minX, x);
    maxX = std::max(maxX, x);
    minY = std::min(minY, y);
    maxY = std::max(maxY, y);
}

static void ExtendBounds3D(const NXOpen::Point3d& point, bool& hasPoint, double& minX, double& maxX, double& minY, double& maxY, double& minZ, double& maxZ)
{
    if (!hasPoint)
    {
        minX = maxX = point.X;
        minY = maxY = point.Y;
        minZ = maxZ = point.Z;
        hasPoint = true;
        return;
    }

    minX = std::min(minX, point.X);
    maxX = std::max(maxX, point.X);
    minY = std::min(minY, point.Y);
    maxY = std::max(maxY, point.Y);
    minZ = std::min(minZ, point.Z);
    maxZ = std::max(maxZ, point.Z);
}

static bool GetBodyMappedBounds(NXOpen::Body* body, double& minX, double& maxX, double& minY, double& maxY, double& minZ, double& maxZ)
{
    if (body == NULL)
    {
        return false;
    }

    bool hasPoint = false;
    vector<NXOpen::Edge*> edges = body->GetEdges();
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        AskEdgeMappedVertices(edges[i], point1, point2);
        ExtendBounds3D(point1, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
        ExtendBounds3D(point2, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
    }

    return hasPoint;
}

static bool GetFaceMappedBounds(NXOpen::Face* face, double& minX, double& maxX, double& minY, double& maxY, double& minZ, double& maxZ)
{
    if (face == NULL)
    {
        return false;
    }

    bool hasPoint = false;
    vector<NXOpen::Edge*> edges = face->GetEdges();
    for (size_t i = 0; i < edges.size(); i++)
    {
        if (edges[i] == NULL)
        {
            continue;
        }

        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        AskEdgeMappedVertices(edges[i], point1, point2);
        ExtendBounds3D(point1, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
        ExtendBounds3D(point2, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
    }

    return hasPoint;
}

static bool GetFaceExactMappedBounds(
    NXOpen::Face* face,
    double& minX,
    double& maxX,
    double& minY,
    double& maxY,
    double& minZ,
    double& maxZ,
    NXOpen::Point3d& corner1,
    NXOpen::Point3d& corner2)
{
    if (face == NULL)
    {
        return false;
    }

    double minCorner[3] = { 0.0, 0.0, 0.0 };
    double directions[3][3] = {};
    double distances[3] = { 0.0, 0.0, 0.0 };
    if (UF_MODL_ask_bounding_box_exact(face->Tag(), NULL_TAG, minCorner, directions, distances) != 0)
    {
        return false;
    }

    bool hasPoint = false;
    for (int x = 0; x <= 1; x++)
    {
        for (int y = 0; y <= 1; y++)
        {
            for (int z = 0; z <= 1; z++)
            {
                double absolutePoint[3] = {
                    minCorner[0] + directions[0][0] * distances[0] * x + directions[1][0] * distances[1] * y + directions[2][0] * distances[2] * z,
                    minCorner[1] + directions[0][1] * distances[0] * x + directions[1][1] * distances[1] * y + directions[2][1] * distances[2] * z,
                    minCorner[2] + directions[0][2] * distances[0] * x + directions[1][2] * distances[1] * y + directions[2][2] * distances[2] * z
                };
                double mappedPoint[3] = { 0.0, 0.0, 0.0 };
                UF_CSYS_map_point(UF_CSYS_WORK_COORDS, absolutePoint, UF_CSYS_ROOT_WCS_COORDS, mappedPoint);
                NXOpen::Point3d point = { mappedPoint[0], mappedPoint[1], mappedPoint[2] };
                ExtendBounds3D(point, hasPoint, minX, maxX, minY, maxY, minZ, maxZ);
            }
        }
    }

    if (!hasPoint)
    {
        return false;
    }

    corner1.X = minX;
    corner1.Y = minY;
    corner1.Z = minZ;
    corner2.X = maxX;
    corner2.Y = maxY;
    corner2.Z = maxZ;
    return true;
}

static NXOpen::Edge* FindNearestMappedVerticalEdgeAtXY(
    const vector<NXOpen::Edge*>& edges,
    double targetX,
    double targetY,
    int zMode,
    double banHou,
    double searchTolerance,
    double columnTolerance,
    double zTolerance,
    double& bestDistance)
{
    bestDistance = std::numeric_limits<double>::max();
    NXOpen::Edge* bestEdge = NULL;
    for (size_t i = 0; i < edges.size(); i++)
    {
        NXOpen::Edge* edge = edges[i];
        if (!IsStraightEdge(edge))
        {
            continue;
        }

        NXOpen::Point3d point1;
        NXOpen::Point3d point2;
        AskEdgeMappedVertices(edge, point1, point2);
        double dx = fabs(point1.X - point2.X);
        double dy = fabs(point1.Y - point2.Y);
        double dz = fabs(point1.Z - point2.Z);
        if (dx > columnTolerance || dy > columnTolerance || dz < zTolerance)
        {
            continue;
        }

        if (zMode == 1)
        {
            if (fabs(point1.Z) > zTolerance && fabs(point2.Z) > zTolerance)
            {
                continue;
            }
        }
        else if (zMode == 2)
        {
            if (point1.Z + banHou > zTolerance && point2.Z + banHou > zTolerance)
            {
                continue;
            }
        }

        double centerX = (point1.X + point2.X) / 2.0;
        double centerY = (point1.Y + point2.Y) / 2.0;
        double distance = sqrt(pow(centerX - targetX, 2) + pow(centerY - targetY, 2));
        if (distance < bestDistance)
        {
            bestDistance = distance;
            bestEdge = edge;
        }
    }

    return bestDistance <= searchTolerance ? bestEdge : NULL;
}

static bool GetBodyProjectedBounds(NXOpen::Body* body, double& minX, double& maxX, double& minY, double& maxY)
{
    double minZ = 0.0;
    double maxZ = 0.0;
    if (GetBodyMappedBounds(body, minX, maxX, minY, maxY, minZ, maxZ))
    {
        return true;
    }

    return false;
}

static bool DetectSkirt(NXOpen::Body* body, double faceMinX, double faceMaxX, double faceMinY, double faceMaxY, double tolerance, SkirtInfo& skirtInfo)
{
    double bodyMinX = 0.0;
    double bodyMaxX = 0.0;
    double bodyMinY = 0.0;
    double bodyMaxY = 0.0;
    if (!GetBodyProjectedBounds(body, bodyMinX, bodyMaxX, bodyMinY, bodyMaxY))
    {
        return false;
    }

    skirtInfo.bodyMinX = bodyMinX;
    skirtInfo.bodyMaxX = bodyMaxX;
    skirtInfo.bodyMinY = bodyMinY;
    skirtInfo.bodyMaxY = bodyMaxY;
    skirtInfo.xMinusWidth = std::max(0.0, faceMinX - bodyMinX);
    skirtInfo.xPlusWidth = std::max(0.0, bodyMaxX - faceMaxX);
    skirtInfo.yMinusWidth = std::max(0.0, faceMinY - bodyMinY);
    skirtInfo.yPlusWidth = std::max(0.0, bodyMaxY - faceMaxY);
    skirtInfo.xMinus = skirtInfo.xMinusWidth > tolerance;
    skirtInfo.xPlus = skirtInfo.xPlusWidth > tolerance;
    skirtInfo.yMinus = skirtInfo.yMinusWidth > tolerance;
    skirtInfo.yPlus = skirtInfo.yPlusWidth > tolerance;
    return true;
}

static int CountSkirtSides(const SkirtInfo& skirtInfo)
{
    return (skirtInfo.xMinus ? 1 : 0) +
        (skirtInfo.xPlus ? 1 : 0) +
        (skirtInfo.yMinus ? 1 : 0) +
        (skirtInfo.yPlus ? 1 : 0);
}

static int CountCornerSkirtSides(const SkirtInfo& skirtInfo, double cornerX, double cornerY,
    double minX, double maxX, double minY, double maxY, double tolerance,
    bool& hasXSkirt, bool& hasYSkirt)
{
    bool atXMinus = fabs(cornerX - minX) < tolerance;
    bool atXPlus = fabs(cornerX - maxX) < tolerance;
    bool atYMinus = fabs(cornerY - minY) < tolerance;
    bool atYPlus = fabs(cornerY - maxY) < tolerance;
    hasXSkirt = (atXMinus && skirtInfo.xMinus) || (atXPlus && skirtInfo.xPlus);
    hasYSkirt = (atYMinus && skirtInfo.yMinus) || (atYPlus && skirtInfo.yPlus);
    return (hasXSkirt ? 1 : 0) + (hasYSkirt ? 1 : 0);
}

static int GetSingleSkirtCutDirection(bool hasXSkirt, bool hasYSkirt)
{
    if (hasXSkirt && !hasYSkirt)
    {
        return 1;
    }
    if (hasYSkirt && !hasXSkirt)
    {
        return 2;
    }
    return 0;
}

