static double GetOuterSkirtCoordinate(double cornerCoordinate, double minCoordinate, double maxCoordinate, double bodyMinCoordinate, double bodyMaxCoordinate)
{
    if (fabs(cornerCoordinate - minCoordinate) < 0.001)
    {
        return bodyMinCoordinate;
    }
    if (fabs(cornerCoordinate - maxCoordinate) < 0.001)
    {
        return bodyMaxCoordinate;
    }
    return cornerCoordinate;
}

static void ClearSelection(NXOpen::BlockStyler::SelectObject* selectionBlock)
{
    if (selectionBlock == NULL)
    {
        return;
    }

    const char* phase = "ClearSelection.GetProperties";
    PropertyList* selectionProps = NULL;
    try
    {
        selectionProps = selectionBlock->GetProperties();
        vector<NXOpen::TaggedObject*> emptySelection;
        phase = "ClearSelection.SetTaggedObjectVector SelectedObjects";
        selectionProps->SetTaggedObjectVector("SelectedObjects", emptySelection);
        delete selectionProps;
        selectionProps = NULL;
    }
    catch (exception& ex)
    {
        if (selectionProps != NULL)
        {
            delete selectionProps;
            selectionProps = NULL;
        }
        ShowBlockStylerError(ex);
    }
}
