//------------------------------------------------------------------------------
//Callback Name: filter_cb
//------------------------------------------------------------------------------
int MenBanSiBian::filter_cb(NXOpen::BlockStyler::UIBlock* block, NXOpen::TaggedObject* selectedObject)
{
    try
    {
        if (block == selectionEdge ||
            (block == selection0 && selectionEdge == NULL && IsSingleCornerMode(enumCreateMode)))
        {
            return IsStraightEdge(GetEdgeFromTaggedObject(selectedObject)) ? UF_UI_SEL_ACCEPT : UF_UI_SEL_REJECT;
        }
        if (block == selection0)
        {
            return GetFaceFromTaggedObject(selectedObject) != NULL ? UF_UI_SEL_ACCEPT : UF_UI_SEL_REJECT;
        }
        return UF_UI_SEL_ACCEPT;
    }
    catch (exception&)
    {
        return UF_UI_SEL_REJECT;
    }
}

